{
  "terms": [
    {
      "term": "ADS (Automatic Disconnection of Supply)",
      "simpleDefinition": "A safety strategy that automatically cuts off power during a fault to prevent electric shock.",
      "anchor": "The 'trip' that happens instantly when a fault is detected.",
      "misconception": "Thinking ADS is just a single fuse; it is actually the whole system of wires and devices working together."
    },
    {
      "term": "TT System",
      "simpleDefinition": "An earthing arrangement where the user provides their own connection to the ground using an electrode.",
      "anchor": "A copper rod driven into the soil outside a building.",
      "misconception": "Assuming the electricity supplier always provides the earth connection."
    },
    {
      "term": "TN-S System",
      "simpleDefinition": "An earthing arrangement where the Neutral and Earth conductors are kept separate all the way from the transformer to the installation.",
      "anchor": "The earth connection clamped to the metal sheath of the incoming supply cable.",
      "misconception": "Thinking the 'S' stands for 'Supply' when it actually stands for 'Separate'."
    },
    {
      "term": "TN-C-S System",
      "simpleDefinition": "An arrangement where Neutral and Earth are combined in the supply cable but separated at the property's intake.",
      "anchor": "Commonly known as PME (Protective Multiple Earthing).",
      "misconception": "Believing the earth and neutral stay combined inside the building's internal circuits."
    },
    {
      "term": "CPC (Circuit Protective Conductor)",
      "simpleDefinition": "The specific wire that connects the metal parts of a circuit (like a light fitting) to the main earth terminal.",
      "anchor": "The green and yellow wire found inside a standard twin and earth cable.",
      "misconception": "Calling every green and yellow wire a CPC; bonding conductors have a different job."
    },
    {
      "term": "Earthing Conductor",
      "simpleDefinition": "The main wire that connects the installation's Main Earthing Terminal to the supplier's earth or the earth electrode.",
      "anchor": "The thick green and yellow cable connecting the consumer unit to the service head.",
      "misconception": "Confusing this single main cable with the many CPCs that go to individual sockets."
    },
    {
      "term": "Main Protective Bonding Conductor",
      "simpleDefinition": "A conductor used to connect metal pipes (like gas or water) to the main earthing terminal to keep them at the same potential.",
      "anchor": "The wire clamped to the copper water main where it enters the house.",
      "misconception": "Thinking bonding is designed to carry fault current from a broken appliance like a CPC does."
    },
    {
      "term": "Protective Device",
      "simpleDefinition": "A component, such as a fuse or circuit breaker, that breaks the circuit when it detects too much current.",
      "anchor": "The MCB (Miniature Circuit Breaker) that you flip back up in the consumer unit.",
      "misconception": "Thinking the device will trip correctly even if there is no earth path provided."
    },
    {
      "term": "Earth Electrode",
      "simpleDefinition": "A metal rod or plate buried in the ground to create a physical connection to the Earth.",
      "anchor": "A 1.2-meter copper rod driven into the ground for a TT system.",
      "misconception": "Thinking every property requires its own earth rod."
    }
  ],
  "anchorPhrases": [
    "Separate (S) means separate all the way.",
    "Combined (C) means joined in the street, split at the house.",
    "The CPC protects the circuit; the Bonding protects the pipes.",
    "TT relies on the soil via an electrode."
  ],
  "misconceptionTargets": [
    "Earthing and bonding are not the same thing.",

{
  "teachChecks": [
    {
      "title": "ADS Component Overview",
      "basicQuestions": [
        {
          "questionText": "What does the abbreviation ADS stand for in electrical safety?",
          "answerGuidance": [
            "Automatic Disconnection of Supply",
            "Automatic Disconnection"
          ]
        },
        {
          "questionText": "Which component in an ADS system is responsible for physically breaking the circuit when a fault is detected?",
          "answerGuidance": [
            "Protective Device",
            "Fuse",
            "Circuit Breaker",
            "MCB"
          ]
        },
        {
          "questionText": "What is the name of the conductor that provides the fault path within an individual circuit?",
          "answerGuidance": [
            "Circuit Protective Conductor",
            "CPC"
          ]
        }
      ],
      "deeperQuestionText": "Why is ADS described as a safety strategy rather than a single component?",
      "deeperAnswerGuidance": [
        "It requires multiple parts working together",
        "Conductors must provide a path for the current",
        "Protective devices must detect the surge and trip",
        "The system relies on the coordination of wires and devices"
      ],
      "hint": "Think of ADS as a team effort where wires provide the path and devices provide the switch-off."
    },
    {
      "title": "Protective Devices and Bonding",
      "basicQuestions": [
        {
          "questionText": "What is the primary purpose of bonding conductors regarding electrical potential?",
          "answerGuidance": [
            "Keep metal parts at the same potential",
            "Equalize voltage",
            "Maintain same voltage"
          ]
        },
        {
          "questionText": "Which specific type of bonding connects metal services like gas and water pipes to the Main Earthing Terminal?",
          "answerGuidance": [
            "Main Protective Bonding",
            "Main Bonding"
          ]
        },
        {
          "questionText": "In which specific high-risk room is supplementary bonding typically installed?",
          "answerGuidance": [
            "Bathroom",
            "Bathrooms"
          ]
        }
      ],
      "deeperQuestionText": "How does bonding protect a person from electric shock if it is not designed to carry fault current back to the source?",
      "deeperAnswerGuidance": [
        "It prevents a voltage difference between two metal surfaces",
        "It ensures all touched metal parts are at the same potential",
        "It stops current flowing through the body if two parts are touched simultaneously",
        "It eliminates the risk of touching two different voltages"
      ],
      "hint": "Protective devices 'cut' the power, while bonding 'links' metal parts to keep them at the same voltage."
    },
    {
      "title": "TT Earthing Systems",
      "basicQuestions": [
        {
          "questionText": "In the TT system code, what does the first letter 'T' indicate about the supplier's transformer?",
          "answerGuidance": [
            "Connected to ground",
            "Earthed",
            "Connected to earth"
          ]
        },
        {
          "questionText": "What component must the installer provide in a TT system because the supplier does not provide an earth terminal?",
          "answerGuidance": [
            "Earth Electrode",
            "Ground rod",
            "Earth rod"
          ]
        },
        {
          "questionText": "What is the common material used for the core of a standard earth electrode?",
          "answerGuidance": [
            "Steel",
            "Copper-plated steel"
          ]
        }
      ],
      "deeperQuestionText": "Why must a TT system rely on the physical mass of earth for the fault return path?",
      "deeperAnswerGuidance": [
        "The supplier does not provide a metallic earth conductor",
        "The fault current must travel through the soil to reach the transformer",
        "The local electrode is the only connection to the return source",
        "The ground itself completes the circuit loop"
      ],
      "hint": "In a TT system, the 'T' at the end means the consumer is responsible for their own connection to the ground."
    },
    {
      "title": "TN-S and TN-C-S Systems",
      "basicQuestions": [
        {
          "questionText": "In a TN-S earthing system, what does the letter 'S' stand for?",
          "answerGuidance": [
            "Separate",
            "Separated"
          ]
        },
        {
          "questionText": "What is the common industry name for a TN-C-S earthing arrangement?",
          "answerGuidance": [
            "PME",
            "Protective Multiple Earthing"
          ]
        },
        {
          "questionText": "In a TN-C-S system, what does the letter 'C' indicate about the Neutral and Earth conductors in the supply cable?",
          "answerGuidance": [
            "Combined",
            "They are one conductor"
          ]
        }
      ],
      "deeperQuestionText": "What is the primary difference in how the earth path is delivered to the property in a TN-S system compared to a TN-C-S system?",
      "deeperAnswerGuidance": [
        "TN-S uses a completely separate wire or cable sheath for earth",
        "TN-C-S combines earth and neutral in the street cable",
        "TN-S has two distinct conductors from the transformer to the intake",
        "TN-C-S only splits the combined conductor at the property intake"
      ],
      "hint": "Look at the letters: S means the wires stay Separate, while C means they start Combined in the street."
    },
    {
      "title": "CPC and Earthing Conductor",
      "basicQuestions": [
        {
          "questionText": "Which conductor connects the entire installation's Main Earthing Terminal to the supplier's earth point?",
          "answerGuidance": [
            "Earthing Conductor",
            "Main earthing conductor"
          ]
        },
        {
          "questionText": "What is the specific name for the earth wire found inside a standard twin-and-earth cable used for a single circuit?",
          "answerGuidance": [
            "Circuit Protective Conductor",
            "CPC"
          ]
        },
        {
          "questionText": "What are the identification colors used for both the CPC and the Earthing Conductor?",
          "answerGuidance": [
            "Green and yellow",
            "Yellow and green"
          ]
        }
      ],
      "deeperQuestionText": "Using the tree analogy, why is the Earthing Conductor considered the 'trunk' of the earthing system?",
      "deeperAnswerGuidance": [
        "It is the single main path for all fault current",
        "All individual CPC branches connect into it via the MET",
        "It carries the total potential fault current out of the building",
        "It is the final link between the installation and the earth source"
      ],
      "hint": "The CPC is for a single circuit; the Earthing Conductor is the main link for the whole building."
    }
  ]
}

{
  "guidedPractice": {
    "title": "Guided Practice: Identifying TN-S Components",
    "objective": "Identify a TN-S system and its bonding components based on a physical description of the intake.",
    "retrievalTextLines": [
      "Scenario: You are inspecting an older industrial unit. The incoming supply cable has a metallic lead sheath.",
      "A clamp is fixed to this metal sheath, and a green and yellow cable runs from this clamp to the Main Earthing Terminal (MET).",
      "From the MET, a separate green and yellow cable is connected to the incoming metallic gas service pipe."
    ],
    "questionText": "Identify the earthing system type described and the specific name of the conductor connected to the gas pipe.",
    "answerGuidance": [
      "TN-S and Main Protective Bonding Conductor",
      "TN-S and Main Protective Bonding",
      "TN-S and bonding"
    ],
    "hint": "Remember: If the earth is taken from the separate metal sheath of the cable, it is 'S' for Separate. Conductors going to pipes are for 'Bonding'."
  },
  "practice": {
    "title": "Practice: Identifying TT Systems",
    "objective": "Identify a TT earthing system and its specific earth connection component.",
    "retrievalTextLines": [
      "Scenario: You are at a remote farm building supplied by overhead lines. The supplier has not provided an earth terminal.",
      "To ensure the ADS system functions, the installer has run a green and yellow cable from the MET to a copper rod driven deep into the soil outside the building."
    ],
    "questionText": "State the earthing system type used in this scenario and the technical name of the component driven into the soil.",
    "answerGuidance": [
      "TT and Earth Electrode",
      "TT system and earth electrode",
      "TT and electrode"
    ],
    "hint": "In this system, the consumer provides their own connection to the mass of earth because the supplier does not provide one."
  }
}

{
  "integrative": {
    "title": "Integrative Close: The ADS Fault Path",
    "objective": "Synthesize the relationship between circuit-level protection (CPC) and installation-level earthing (Earthing Conductor) within a TN-C-S system.",
    "retrievalTextLines": [
      "In a TN-C-S (PME) installation, the supplier provides a combined neutral and earth path to the property, which is then split at the intake.",
      "For Automatic Disconnection of Supply (ADS) to work, every part of the path must be continuous, from the individual appliance back to the transformer.",
      "This path relies on different conductors performing specific roles at different stages of the installation."
    ],
    "questionText": "In a TN-C-S system, a fault occurs in a metal light fitting. Describe the sequence of green-and-yellow conductors the fault current must travel through to reach the supplier's intake, and explain the specific role of the Earthing Conductor in this sequence compared to the CPC.",
    "answerGuidance": [
      "The fault current travels through the CPC (Circuit Protective Conductor) of the lighting circuit to the Main Earthing Terminal (MET).",
      "From the MET, the current travels through the Earthing Conductor to the supplier's combined terminal.",
      "The CPC provides protection for that specific circuit, whereas the Earthing Conductor serves as the main link connecting the entire installation's MET to the supplier's earth path."
    ],
    "hint": "Think about the 'tree' analogy: one conductor handles the 'branch' (the light) and the other handles the 'trunk' (the whole house) to get the current back to the supplier."
  }
}

